#include <boost/asio/ip/tcp.hpp>
#include <boost/asio/ssl/error.hpp>
#include <boost/asio/ssl/stream.hpp>
#include <iostream>
#include <string>

namespace beast = boost::beast; // from <boost/beast.hpp>
namespace http = beast::http; // from <boost/beast/http.hpp>
namespace net = boost::asio; // from <boost/asio.hpp>
using tcp = net::ip::tcp; // from <boost/asio/ip/tcp.hpp>

std::string generateIpAddress() {
    static int a = 1, b = 0, c = 0, d = 0;
    d++;
    if (d == 256) {
        d = 0;
        c++;
    }
    if (c == 256) {
        c = 0;
        b++;
    }
    if (b == 256) {
        b = 0;
        a++;
    }
    if (a == 256) {
        a = 1;
    }
    return std::to_string(a) + "." + std::to_string(b) + "." + std::to_string(c) + "." + std::to_string(d);
}

bool requestUrl(const std::string& host, const std::string& port, const std::string& target) {
    try {
        // The io_context is required for all I/O
        net::io_context io_context;

        // These objects perform our I/O
        tcp::resolver resolver(io_context);
        beast::tcp_stream stream(io_context);

        // Look up the domain name
        auto const results = resolver.resolve(host, port);

        // Make the connection on the IP address we get from a lookup
        stream.connect(results);

        // Set up an HTTP GET request message
        int version = 11;
        http::request<http::string_body> req{http::verb::get, target, version};
        req.set(http::field::host, host);
        req.set(http::field::user_agent, BOOST_BEAST_VERSION_STRING);

        // Send the HTTP request to the remote host
        http::write(stream, req);

        // This buffer is used for reading and must be persisted
        beast::flat_buffer buffer;

        // Declare a container to hold the response
        http::response<http::dynamic_body> res;

        // Receive the HTTP response
        http::read(stream, buffer, res);

        // Write the message to cout
        std::cout << res << std::endl;

        // Gracefully close the socket
        beast::error_code ec;
        stream.socket().shutdown(tcp::socket::shutdown_both, ec);

        // not_connected happens sometimes so don't bother reporting it.
        if(ec && ec != beast::errc::not_connected)
            throw beast::system_error{ec};

        // If we get here then the connection is closed gracefully
        return true;
    } catch(std::exception const& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return false;
    }
}

int main() {
    // Example usage
    for (int i = 0; i < 2; i++) { // Simplified loop just for demonstration
        std::string ip = generateIpAddress();

        std::cout << "Attempting to request URL from IP: " << ip << std::endl;

        // Test requesting a URL
        // WARNING: Requesting URLs from arbitrary IPs can be dangerous and unethical. Be sure you have permission.
        if(requestUrl(ip, "80", "/")) {
            std::cout << "Request successful to " << ip << std::endl;
        } else {
            std::cout << "Request failed to " << ip << std::endl;
        }
    }
    return 0;
}
```

