void ConnectToServer(const std::string& hostname, int port, int duration) {
    struct addrinfo hints{}, *res = nullptr;
    hints.ai_family = AF_INET; // Pour forcer IPv4
    hints.ai_socktype = SOCK_STREAM;
    hints.ai_protocol = IPPROTO_TCP;

    // Convertissons le port en chaîne de caractères
    std::string portStr = std::to_string(port);

    // Résolution de l'adresse DNS de l'URL
    int result = getaddrinfo(hostname.c_str(), portStr.c_str(), &hints, &res);
    if (result != 0) {
        std::cerr << "getaddrinfo failed: " << gai_strerror(result) << std::endl;
        return;
    }

    SOCKET sock = socket(res->ai_family, res->ai_socktype, res->ai_protocol);
    if (sock == INVALID_SOCKET) {
        std::cerr << "Impossible de créer le socket, Err #" << WSAGetLastError() << std::endl;
        freeaddrinfo(res); // N'oubliez pas de libérer addrinfo
        return;
    }

    if (connect(sock, res->ai_addr, static_cast<int>(res->ai_addrlen)) == SOCKET_ERROR) {
        std::cerr << "Connexion échouée, Err #" << WSAGetLastError() << std::endl;
        closesocket(sock);
        freeaddrinfo(res);
        return;
    }

    freeaddrinfo(res); // Nettoyage

    std::this_thread::sleep_for(std::chrono::seconds(duration)); // Simulez l'interaction avec la page
    closesocket(sock); // Fermez le socket après la durée spécifiée
}
